INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '2264d690-6f86-429a-895a-6249e5c7d5e4',
  '00000000-0000-0000-0000-000000000001',
  $escape$seaborn + Polars — Fast Data Prep Before You Plot$escape$,
  $escape$seaborn's plotting functions expect pandas-compatible DataFrames, but that doesn't mean you have to wrangle data with pandas. Polars' lazy API lets you chain filter, group_by, and agg operations that only execute when you call .collect() — no intermediate copies, no wasted memory. The expressions API (pl.col("score").mean().over("category")) replaces verbose pandas groupby chains with a single readable line. For datasets over ~500K rows, the speedup before hitting sns.barplot() or sns.FacetGrid() is significant. The handoff is one line: df.collect().to_pandas(). Use Polars for all upstream transforms — filtering outliers, computing rolling stats, pivoting — then hand a lean, pre-aggregated pandas DataFrame to seaborn. Switch when your sns.histplot() or sns.pairplot() prep code is the bottleneck, not the render. Keep Polars out of the seaborn call itself; it doesn't understand Polars Series as hue or x arguments natively.$escape$,
  $escape$import polars as pl
import seaborn as sns
import matplotlib.pyplot as plt

lf = pl.scan_parquet("events.parquet")

agg_df = (
    lf
    .filter(pl.col("duration_ms") > 0)
    .with_columns(pl.col("score").mean().over("category").alias("cat_mean"))
    .group_by("category")
    .agg(pl.col("score").median().alias("median_score"))
    .collect()
    .to_pandas()
)

sns.barplot(data=agg_df, x="category", y="median_score")
plt.tight_layout()
plt.show()$escape$,
  $escape$python$escape$,
